   530→  for (const auto& api_state : api_state_) {
   531→    for (auto watch : api_state.second->watches_) {
   532→      watch->callbacks_.onConfigUpdateFailed(
   533→          Envoy::Config::ConfigUpdateFailureReason::ConnectionFailure, nullptr);
