   270→template <class S, class F, class RQ, class RS>
   271→void GrpcMuxImpl<S, F, RQ, RS>::handleEstablishedStream() {
   272→  ENVOY_LOG(debug, "GrpcMuxImpl stream successfully established");
   273→  for (auto& [type_url, subscription_state] : subscriptions_) {
   274→    subscription_state->markStreamFresh();
   275→  }
