   282→template <class S, class F, class RQ, class RS>
   283→void GrpcMuxImpl<S, F, RQ, RS>::handleStreamEstablishmentFailure() {
   284→  ENVOY_LOG(debug, "GrpcMuxImpl stream failed to establish");
   285→  // If this happens while Envoy is still initializing, the onConfigUpdateFailed() we ultimately
   286→  // call on CDS will cause LDS to start up, which adds to subscriptions_ here. So, to avoid a
   287→  // crash, the iteration needs to dance around a little: collect pointers to all
   288→  // SubscriptionStates, call on all those pointers we haven't yet called on, repeat if there are
   289→  // now more SubscriptionStates.
   290→  absl::flat_hash_map<std::string, S*> all_subscribed;
   291→  absl::flat_hash_map<std::string, S*> already_called;
   292→  do {
   293→    for (auto& [type_url, subscription_state] : subscriptions_) {
   294→      all_subscribed[type_url] = subscription_state.get();
   295→    }
   296→    for (auto& sub : all_subscribed) {
   297→      if (already_called.insert(sub).second) { // insert succeeded ==> not already called
   298→        sub.second->handleEstablishmentFailure();
   299→      }
   300→    }
   301→  } while (all_subscribed.size() != subscriptions_.size());
   302→}
