    64→CdsApiImpl::onConfigUpdate(const std::vector<Config::DecodedResourceRef>& added_resources,
    65→                           const Protobuf::RepeatedPtrField<std::string>& removed_resources,
    66→                           const std::string& system_version_info) {
    67→  auto exception_msgs =
    68→      helper_.onConfigUpdate(added_resources, removed_resources, system_version_info);
    69→  runInitializeCallbackIfAny();
    70→  if (!exception_msgs.empty()) {
    71→    return absl::InvalidArgumentError(
    72→        fmt::format("Error adding/updating cluster(s) {}", absl::StrJoin(exception_msgs, ", ")));
    73→  }
    74→  return absl::OkStatus();
    75→}
